-- ===== 과일 (1-15) =====
INSERT INTO products (name, category_id, price, description, active, bay, level, position_index, stock) VALUES
('청송 꿀사과', 'cat-fresh-fruits', 3.50, '경북 청송에서 재배한 프리미엄 꿀사과입니다. 당도가 높고 아삭한 식감이 특징이며, 비타민C가 풍부해 피로 회복과 면역력 강화에 도움을 줍니다. 냉장 보관 시 2주간 신선하게 드실 수 있습니다.', true, 'A', 1, 0, 100),
('청송 부사 사과', 'cat-fresh-fruits', 2.90, '국내 최고 품질의 청송 부사 사과입니다. 과즙이 풍부하고 새콤달콤한 맛이 일품입니다. 아침 식사 대용이나 간식으로 좋으며, 다이어트 중인 분들에게도 추천드립니다.', true, 'A', 1, 1, 80),
('제주 감귤', 'cat-fresh-fruits', 1.90, '제주도 서귀포에서 수확한 싱싱한 감귤입니다. 새콤달콤한 맛과 풍부한 비타민C가 특징입니다. 껍질째 먹어도 좋을 만큼 깨끗하게 관리되었으며, 겨울철 감기 예방에 효과적입니다.', true, 'A', 1, 2, 150),
('고당도 배', 'cat-fresh-fruits', 4.20, '나주 지역에서 재배한 프리미엄 황금배입니다. 당도 13브릭스 이상의 고당도 배로, 수분이 풍부하고 시원한 맛이 특징입니다. 소화를 돕고 기침 완화에 효과가 있습니다.', true, 'A', 2, 0, 60),
('샤인머스캣', 'cat-fresh-fruits', 9.20, '씨없는 포도의 대명사 샤인머스캣입니다. 껍질째 먹을 수 있으며, 망고향이 나는 달콤한 맛이 특징입니다. 선물용으로도 인기가 높으며, 와인 안주로도 잘 어울립니다.', true, 'A', 2, 1, 40),
('캠벨 포도', 'cat-fresh-fruits', 5.00, '국산 캠벨 포도입니다. 진한 포도향과 달콤한 맛이 특징이며, 씨가 있지만 과육이 풍부합니다. 주스나 잼을 만들기에도 좋습니다.', true, 'A', 2, 2, 50),
('성주 참외', 'cat-fresh-fruits', 6.15, '성주 지역 특산물인 참외입니다. 아삭한 식감과 달콤한 과즙이 특징이며, 여름철 수분 보충에 탁월합니다. 칼륨이 풍부해 붓기 제거에 도움을 줍니다.', true, 'A', 3, 0, 70),
('딸기', 'cat-fresh-fruits', 7.30, '논산 지역에서 재배한 설향 딸기입니다. 크기가 크고 당도가 높으며, 비타민C와 안토시아닌이 풍부합니다. 그냥 드셔도 좋고, 케이크 토핑이나 스무디로 활용하기 좋습니다.', true, 'A', 3, 1, 45),
('바나나', 'cat-tropical-fruits', 2.70, '필리핀산 고산지 바나나입니다. 당도가 높고 식감이 부드러워 어린이 간식으로 인기가 많습니다. 운동 전후 에너지 보충에 좋으며, 칼륨이 풍부해 근육 경련 예방에 도움을 줍니다.', true, 'B', 1, 0, 200),
('망고', 'cat-tropical-fruits', 5.80, '태국산 카라바오 망고입니다. 달콤한 향과 부드러운 과육이 특징이며, 비타민A와 베타카로틴이 풍부합니다. 스무디, 샐러드, 디저트 등 다양하게 활용할 수 있습니다.', true, 'B', 1, 1, 30),
('파인애플', 'cat-tropical-fruits', 4.60, '필리핀산 스위트 파인애플입니다. 새콤달콤한 맛과 풍부한 과즙이 특징입니다. 브로멜린 효소가 함유되어 소화를 돕고, 고기 요리와 함께 먹으면 좋습니다.', true, 'B', 1, 2, 25),
('키위', 'cat-tropical-fruits', 3.50, '뉴질랜드산 그린 키위입니다. 새콤한 맛과 부드러운 식감이 특징이며, 비타민C가 오렌지의 2배 이상 함유되어 있습니다. 피부 미용과 면역력 강화에 도움을 줍니다.', true, 'B', 2, 0, 60),
('건포도', 'cat-dried-fruits', 2.30, '칠레산 건포도입니다. 달콤한 맛과 쫄깃한 식감이 특징이며, 철분과 식이섬유가 풍부합니다. 빵, 쿠키, 시리얼에 넣어 드시거나 간식으로 즐기기 좋습니다.', true, 'B', 2, 1, 80),
('건망고', 'cat-dried-fruits', 4.20, '필리핀산 건조 망고입니다. 망고 본연의 달콤한 맛이 농축되어 있으며, 비타민A가 풍부합니다. 간식이나 요거트 토핑으로 인기가 많습니다.', true, 'B', 2, 2, 50),

-- ===== 채소 (16-30) =====
('유기농 시금치', 'cat-leafy', 2.70, '국내산 유기농 시금치입니다. 철분과 엽산이 풍부하여 빈혈 예방에 효과적이며, 비타민A와 C도 다량 함유되어 있습니다. 나물, 국, 샐러드 등 다양하게 활용할 수 있습니다.', true, 'C', 1, 0, 100),
('로메인 상추', 'cat-leafy', 2.15, '신선한 로메인 상추입니다. 아삭한 식감과 씁쓸한 맛이 특징이며, 시저 샐러드의 주재료로 사용됩니다. 수분 함량이 높아 다이어트 식품으로 인기가 많습니다.', true, 'C', 1, 1, 80),
('청경채', 'cat-leafy', 1.90, '국내산 청경채입니다. 아삭한 식감과 담백한 맛이 특징이며, 칼슘과 비타민C가 풍부합니다. 볶음요리, 국, 샤브샤브 등에 잘 어울립니다.', true, 'C', 1, 2, 70),
('양배추', 'cat-leafy', 1.50, '국내산 양배추입니다. 비타민U가 풍부하여 위 건강에 좋으며, 식이섬유도 풍부합니다. 샐러드, 쌈, 볶음 등 다양한 요리에 활용할 수 있습니다.', true, 'C', 2, 0, 120),
('당근', 'cat-root', 1.15, '국내산 주황당근입니다. 베타카로틴이 풍부하여 눈 건강과 피부 미용에 좋습니다. 아삭한 식감으로 생으로 먹어도 좋고, 조림이나 볶음 요리에도 잘 어울립니다.', true, 'C', 2, 1, 150),
('감자', 'cat-root', 2.30, '강원도 고랭지 감자입니다. 포슬포슬한 식감과 고소한 맛이 특징이며, 탄수화물과 비타민C가 풍부합니다. 구이, 조림, 튀김 등 다양한 요리에 활용할 수 있습니다.', true, 'C', 2, 2, 200),
('고구마', 'cat-root', 3.10, '해남 꿀고구마입니다. 달콤한 맛과 촉촉한 식감이 특징이며, 식이섬유와 비타민E가 풍부합니다. 찐 고구마, 구운 고구마, 고구마 라떼 등으로 즐길 수 있습니다.', true, 'C', 3, 0, 180),
('양파', 'cat-root', 1.50, '국내산 양파입니다. 매운맛과 단맛이 조화를 이루며, 퀘르세틴 성분이 혈관 건강에 도움을 줍니다. 거의 모든 요리에 활용되는 필수 식재료입니다.', true, 'C', 3, 1, 250),
('마늘', 'cat-root', 6.15, '의성 마늘입니다. 알리신 성분이 풍부하여 면역력 강화와 항균 효과가 있습니다. 한국 요리의 기본 양념으로, 볶음, 찌개, 구이 등에 필수적입니다.', true, 'C', 3, 2, 100),
('새송이버섯', 'cat-mushroom', 2.70, '국내산 새송이버섯입니다. 쫄깃한 식감과 고소한 맛이 특징이며, 칼로리가 낮아 다이어트 식품으로 인기가 많습니다. 구이, 볶음, 전골 등에 잘 어울립니다.', true, 'D', 1, 0, 80),
('표고버섯', 'cat-mushroom', 4.60, '국내산 표고버섯입니다. 감칠맛이 풍부하여 육수나 조림에 좋으며, 비타민D가 풍부합니다. 말린 표고버섯은 더욱 진한 맛을 냅니다.', true, 'D', 1, 1, 60),
('팽이버섯', 'cat-mushroom', 1.15, '국내산 팽이버섯입니다. 아삭한 식감과 담백한 맛이 특징이며, 식이섬유가 풍부합니다. 전골, 샤브샤브, 볶음 등에 잘 어울립니다.', true, 'D', 1, 2, 120),

-- ===== 유제품 (31-45) =====
('서울우유 1L', 'cat-milk', 2.15, '서울우유 1등급 원유로 만든 신선한 우유입니다. 칼슘과 단백질이 풍부하여 성장기 어린이와 뼈 건강이 중요한 성인에게 좋습니다. 냉장 보관 필수입니다.', true, 'E', 1, 0, 100),
('매일 저지방우유', 'cat-milk', 1.90, '매일유업의 저지방 우유입니다. 일반 우유 대비 지방 함량을 50% 줄여 칼로리가 낮습니다. 다이어트 중인 분이나 건강을 생각하는 분께 추천합니다.', true, 'E', 1, 1, 80),
('남양 초콜릿 우유', 'cat-milk', 1.15, '남양유업의 달콤한 초콜릿 우유입니다. 어린이들이 좋아하는 달콤한 맛으로, 칼슘도 함께 섭취할 수 있습니다. 간식이나 학교 급식용으로 인기가 많습니다.', true, 'E', 1, 2, 150),
('상하목장 유기농 우유', 'cat-milk', 3.50, '상하목장의 유기농 인증 우유입니다. 청정 지역에서 자란 젖소의 우유로 만들어 신선하고 깨끗합니다. 아이 있는 가정에서 많이 찾는 프리미엄 우유입니다.', true, 'E', 2, 0, 60),
('체다 슬라이스 치즈', 'cat-cheese', 4.20, '고소한 체다 치즈를 슬라이스로 편리하게 만든 제품입니다. 샌드위치, 햄버거, 토스트에 올려 드시면 부드럽게 녹아 풍미를 더해줍니다.', true, 'E', 2, 1, 70),
('모짜렐라 치즈', 'cat-cheese', 5.40, '이탈리아 스타일 모짜렐라 치즈입니다. 쭉쭉 늘어나는 식감이 특징이며, 피자, 그라탕, 샐러드에 잘 어울립니다. 단백질과 칼슘이 풍부합니다.', true, 'E', 2, 2, 50),
('까망베르 치즈', 'cat-cheese', 9.20, '프랑스산 까망베르 치즈입니다. 부드럽고 크리미한 식감과 고소한 향이 특징입니다. 와인 안주로 최고이며, 크래커나 과일과 함께 즐기기 좋습니다.', true, 'E', 3, 0, 30),
('빙그레 플레인 요거트', 'cat-yogurt', 2.30, '빙그레 플레인 요거트입니다. 유산균이 살아있어 장 건강에 도움을 주며, 단백질과 칼슘도 풍부합니다. 그대로 드시거나 과일, 그래놀라와 함께 즐기세요.', true, 'E', 3, 1, 100),
('그릭 요거트', 'cat-yogurt', 3.50, '진하고 걸쭉한 그릭 요거트입니다. 일반 요거트보다 단백질 함량이 2배 높으며, 포만감이 오래 지속됩니다. 다이어트 식품으로 인기가 많습니다.', true, 'E', 3, 2, 80),
('딸기 요거트', 'cat-yogurt', 1.15, '달콤한 딸기가 들어간 과일 요거트입니다. 어린이 간식으로 인기가 많으며, 유산균이 함유되어 장 건강에 좋습니다.', true, 'F', 1, 0, 120),
('블루베리 요거트', 'cat-yogurt', 1.25, '상큼한 블루베리가 들어간 요거트입니다. 안토시아닌이 풍부한 블루베리와 유산균을 함께 섭취할 수 있습니다. 눈 건강과 장 건강을 동시에 챙기세요.', true, 'F', 1, 1, 100),

-- ===== 육류 (46-55) =====
('한우 등심 1등급', 'cat-beef', 34.60, '국내산 한우 1등급 등심입니다. 마블링이 풍부하고 육즙이 살아있어 스테이크로 구워 드시면 최고의 맛을 느낄 수 있습니다. 냉장 보관하시고 구매 후 3일 이내 드시기를 권장합니다.', true, 'F', 2, 0, 20),
('한우 갈비살', 'cat-beef', 29.20, '국내산 한우 갈비살입니다. 부드러운 식감과 진한 육향이 특징입니다. 구이용으로 최적이며, 양념 갈비로 만들어도 맛있습니다.', true, 'F', 2, 1, 25),
('호주산 안심', 'cat-beef', 21.50, '호주산 청정 소고기 안심입니다. 지방이 적고 부드러운 식감이 특징입니다. 스테이크, 로스트비프, 타르타르 등에 적합합니다.', true, 'F', 2, 2, 30),
('국내산 돼지 삼겹살', 'cat-pork', 13.80, '국내산 돼지 삼겹살입니다. 적당한 지방층과 쫄깃한 식감이 특징입니다. 직화 구이로 드시면 고소한 맛이 일품입니다. 상추, 마늘과 함께 드세요.', true, 'G', 1, 0, 50),
('목살', 'cat-pork', 12.30, '국내산 돼지 목살입니다. 삼겹살보다 담백하면서도 육즙이 풍부합니다. 구이, 불고기, 수육 등 다양한 요리에 활용할 수 있습니다.', true, 'G', 1, 1, 45),
('돼지 앞다리살', 'cat-pork', 9.20, '국내산 돼지 앞다리살입니다. 지방이 적고 단백질이 풍부합니다. 불고기, 제육볶음, 찌개에 넣어 드시면 좋습니다.', true, 'G', 1, 2, 60),
('닭가슴살', 'cat-chicken', 6.15, '국내산 닭가슴살입니다. 고단백 저지방 식품으로 다이어트와 근육 운동하는 분들에게 필수입니다. 샐러드, 볶음, 구이 등에 활용하세요.', true, 'G', 2, 0, 80),
('닭다리살', 'cat-chicken', 7.30, '국내산 닭다리살입니다. 부드럽고 육즙이 풍부하며, 구이나 조림에 적합합니다. 어린이들이 좋아하는 부위입니다.', true, 'G', 2, 1, 70),
('닭볶음탕용', 'cat-chicken', 8.50, '닭볶음탕에 최적화된 손질된 닭고기입니다. 적당한 크기로 잘라 바로 조리할 수 있습니다. 감자, 당근과 함께 매콤하게 조리하세요.', true, 'G', 2, 2, 55),
('훈제오리', 'cat-chicken', 10.80, '국내산 훈제오리입니다. 훈연 과정을 거쳐 특유의 향과 쫄깃한 식감이 특징입니다. 쌈 채소와 함께 드시거나 볶음으로 즐기세요.', true, 'G', 3, 0, 40),

-- ===== 수산물 (56-65) =====
('노르웨이 생연어', 'cat-fish', 13.80, '노르웨이산 신선한 생연어입니다. 오메가3가 풍부하여 심혈관 건강에 좋으며, 회로 드시거나 스테이크로 구워 드셔도 맛있습니다.', true, 'H', 1, 0, 30),
('고등어', 'cat-fish', 4.60, '국내산 고등어입니다. DHA가 풍부하여 두뇌 건강에 좋습니다. 구이, 조림, 찜 등 다양하게 즐길 수 있는 국민 생선입니다.', true, 'H', 1, 1, 50),
('갈치', 'cat-fish', 11.50, '제주산 은갈치입니다. 살이 부드럽고 비린내가 적습니다. 구이나 조림으로 드시면 밥반찬으로 최고입니다.', true, 'H', 1, 2, 35),
('광어 회', 'cat-fish', 19.20, '국내산 활 광어 회입니다. 쫄깃한 식감과 담백한 맛이 특징입니다. 신선도가 중요하므로 구매 당일 드시기를 권장합니다.', true, 'H', 2, 0, 20),
('새우', 'cat-shellfish', 9.20, '베트남산 흰다리새우입니다. 탱글탱글한 식감과 달콤한 맛이 특징입니다. 찜, 구이, 튀김 등 다양하게 즐길 수 있습니다.', true, 'H', 2, 1, 45),
('홍합', 'cat-shellfish', 3.80, '국내산 홍합입니다. 철분과 아연이 풍부하여 빈혈 예방에 좋습니다. 홍합탕, 찜, 파스타에 활용하세요.', true, 'H', 2, 2, 60),
('바지락', 'cat-shellfish', 3.50, '국내산 바지락입니다. 시원한 국물 맛을 내는 데 최고입니다. 바지락 칼국수, 된장찌개, 봉골레 파스타에 활용하세요.', true, 'H', 3, 0, 70),
('오징어', 'cat-fish', 6.15, '국내산 오징어입니다. 쫄깃한 식감이 특징이며, 타우린이 풍부해 피로 회복에 좋습니다. 볶음, 구이, 젓갈 등에 활용하세요.', true, 'H', 3, 1, 55),
('낙지', 'cat-fish', 16.90, '국내산 세발낙지입니다. 부드럽고 쫄깃한 식감이 특징이며, 스테미나 음식으로 인기가 많습니다. 낙지볶음, 연포탕에 잘 어울립니다.', true, 'H', 3, 2, 25),
('전복', 'cat-shellfish', 23.10, '완도산 전복입니다. 바다의 산삼이라 불리며, 간 건강에 좋은 아르기닌이 풍부합니다. 죽, 찜, 버터구이로 즐기세요.', true, 'I', 1, 0, 20),

-- ===== 음료 (66-75) =====
('삼다수 2L', 'cat-water', 1.15, '제주 화산암반수 삼다수입니다. 미네랄이 풍부하고 깨끗한 물입니다. 일상 음용수로 적합하며, 가정에서 많이 찾는 생수입니다.', true, 'I', 2, 0, 300),
('에비앙', 'cat-water', 2.30, '프랑스 알프스산 프리미엄 생수 에비앙입니다. 미네랄 밸런스가 좋고 부드러운 맛이 특징입니다.', true, 'I', 2, 1, 100),
('페리에 탄산수', 'cat-water', 1.90, '프랑스산 천연 탄산수 페리에입니다. 청량감 있는 탄산과 깔끔한 맛이 특징입니다. 식사 시 음료나 칵테일 베이스로 좋습니다.', true, 'I', 2, 2, 80),
('오렌지 주스', 'cat-juice', 3.50, '플로리다산 오렌지로 만든 100% 착즙 주스입니다. 비타민C가 풍부하고 상큼한 맛이 특징입니다. 아침 식사와 함께 드시면 좋습니다.', true, 'I', 3, 0, 60),
('사과 주스', 'cat-juice', 3.10, '국내산 사과로 만든 100% 착즙 주스입니다. 달콤하고 깔끔한 맛이 특징이며, 어린이 간식으로 인기가 많습니다.', true, 'I', 3, 1, 70),
('토마토 주스', 'cat-juice', 2.70, '국내산 완숙 토마토로 만든 주스입니다. 라이코펜이 풍부하여 항산화 효과가 있습니다. 건강을 생각하는 분들에게 추천합니다.', true, 'I', 3, 2, 50),
('아메리카노 원두커피', 'cat-coffee', 9.20, '콜롬비아산 원두로 만든 프리미엄 원두커피입니다. 깊은 풍미와 부드러운 산미가 특징입니다. 드립커피 또는 에스프레소로 즐기세요.', true, 'J', 1, 0, 40),
('녹차 티백', 'cat-coffee', 6.15, '보성 녹차로 만든 티백입니다. 카테킨이 풍부하여 항산화 효과가 있으며, 식후 마시면 소화를 돕습니다. 20개입입니다.', true, 'J', 1, 1, 60),
('캐모마일 차', 'cat-coffee', 5.40, '독일산 캐모마일로 만든 허브차입니다. 은은한 향과 부드러운 맛이 특징이며, 취침 전 마시면 숙면에 도움을 줍니다.', true, 'J', 1, 2, 50),
('콤부차', 'cat-beverages', 3.50, '발효 녹차로 만든 콤부차입니다. 프로바이오틱스가 함유되어 장 건강에 좋습니다. 상큼하고 청량한 맛이 특징입니다.', true, 'J', 2, 0, 70),

-- ===== 과자/스낵 (76-85) =====
('포카칩', 'cat-chips', 1.50, '오리온 포카칩입니다. 바삭한 감자칩에 고소한 시즈닝이 더해져 중독성 있는 맛입니다. 맥주 안주나 영화 간식으로 인기가 많습니다.', true, 'J', 3, 0, 150),
('프링글스 오리지널', 'cat-chips', 2.70, '프링글스 오리지널 맛입니다. 균일한 모양과 바삭한 식감이 특징입니다. 휴대하기 편한 원통형 포장으로 어디서나 즐길 수 있습니다.', true, 'J', 3, 1, 100),
('꼬깔콘', 'cat-chips', 1.15, '롯데 꼬깔콘입니다. 고소한 옥수수 맛과 바삭한 식감이 특징입니다. 남녀노소 모두 좋아하는 국민 스낵입니다.', true, 'J', 3, 2, 120),
('하리보 골드베렌', 'cat-candy', 2.30, '독일 하리보 젤리입니다. 탱글탱글한 식감과 다양한 과일 맛이 특징입니다. 어린이 간식으로 인기가 많습니다.', true, 'K', 1, 0, 80),
('자일리톨 껌', 'cat-candy', 1.90, '롯데 자일리톨 껌입니다. 충치 예방에 도움을 주는 자일리톨이 함유되어 있습니다. 식후 치아 관리에 좋습니다.', true, 'K', 1, 1, 100),
('마이쮸', 'cat-candy', 0.80, '크라운 마이쮸입니다. 쫀득한 식감과 달콤한 과일 맛이 특징입니다. 휴대하기 편해 언제 어디서나 즐길 수 있습니다.', true, 'K', 1, 2, 150),
('가나 초콜릿', 'cat-chocolate', 1.50, '롯데 가나 밀크 초콜릿입니다. 부드럽고 달콤한 맛이 특징이며, 어린 시절 추억의 맛입니다. 선물용으로도 좋습니다.', true, 'K', 2, 0, 100),
('페레로 로쉐', 'cat-chocolate', 9.20, '이탈리아 페레로 로쉐 초콜릿입니다. 바삭한 웨하스와 헤이즐넛, 부드러운 초콜릿의 조화가 일품입니다. 고급 선물용으로 인기가 많습니다.', true, 'K', 2, 1, 40),
('킷캣', 'cat-chocolate', 1.15, '네슬레 킷캣입니다. 바삭한 웨하스에 밀크 초콜릿을 입힌 제품입니다. 휴식 시간에 즐기기 좋은 간식입니다.', true, 'K', 2, 2, 90),
('오레오', 'cat-chocolate', 1.90, '오레오 쿠키입니다. 바삭한 초콜릿 쿠키 사이에 크림이 들어있습니다. 우유에 찍어 먹으면 더욱 맛있습니다.', true, 'K', 3, 0, 80),

-- ===== 냉동식품 (86-92) =====
('비비고 왕교자', 'cat-frozen-meal', 6.50, 'CJ 비비고 왕교자입니다. 풍부한 고기와 채소 속이 특징이며, 구이, 찜, 전골에 모두 잘 어울립니다. 간편하게 조리할 수 있어 인기가 많습니다.', true, 'L', 1, 0, 70),
('풀무원 생면식감 라면', 'cat-frozen-meal', 4.60, '풀무원 냉동 라면입니다. 쫄깃한 생면 식감이 특징이며, 전자레인지로 간편하게 조리할 수 있습니다.', true, 'L', 1, 1, 60),
('오뚜기 볶음밥', 'cat-frozen-meal', 4.20, '오뚜기 냉동 볶음밥입니다. 전자레인지로 3분이면 완성됩니다. 바쁜 아침이나 야식으로 좋습니다.', true, 'L', 1, 2, 80),
('하겐다즈 바닐라', 'cat-ice-cream', 6.90, '하겐다즈 바닐라 아이스크림입니다. 마다가스카르산 바닐라빈으로 만든 프리미엄 아이스크림입니다. 진하고 깊은 바닐라 향이 특징입니다.', true, 'L', 2, 0, 30),
('메로나', 'cat-ice-cream', 1.15, '빙그레 메로나입니다. 달콤한 메론 맛과 시원한 청량감이 특징입니다. 여름철 국민 아이스크림으로 사랑받고 있습니다.', true, 'L', 2, 1, 100),
('월드콘', 'cat-ice-cream', 1.50, '롯데 월드콘입니다. 바삭한 콘 과자에 부드러운 아이스크림이 들어있습니다. 초콜릿, 바닐라 맛이 인기가 많습니다.', true, 'L', 2, 2, 80),
('설빙 인절미 아이스', 'cat-ice-cream', 4.60, '설빙 인절미 아이스바입니다. 쫀득한 인절미와 콩고물의 조화가 일품입니다. 한국 전통 디저트를 아이스크림으로 즐기세요.', true, 'L', 3, 0, 50),

-- ===== 베이커리 (93-97) =====
('파리바게뜨 식빵', 'cat-bread', 2.70, '파리바게뜨 프리미엄 식빵입니다. 부드럽고 촉촉한 식감이 특징입니다. 토스트, 샌드위치에 활용하세요.', true, 'M', 1, 0, 50),
('크로와상', 'cat-bread', 1.90, '버터 풍미 가득한 크로와상입니다. 겉은 바삭하고 속은 부드럽습니다. 아침 식사나 브런치에 커피와 함께 즐기세요.', true, 'M', 1, 1, 40),
('바게트', 'cat-bread', 2.30, '프랑스식 바게트입니다. 겉은 바삭하고 속은 쫄깃합니다. 스프와 함께 먹거나 샌드위치로 활용하세요.', true, 'M', 1, 2, 35),
('딸기 케이크', 'cat-cake', 21.50, '생딸기가 올라간 프리미엄 딸기 케이크입니다. 부드러운 생크림과 촉촉한 시트가 특징입니다. 생일, 기념일에 어울립니다.', true, 'M', 2, 0, 15),
('티라미수', 'cat-cake', 13.80, '이탈리아식 티라미수입니다. 에스프레소에 적신 레이디핑거와 마스카포네 치즈의 조화가 일품입니다. 커피와 함께 즐기세요.', true, 'M', 2, 1, 20),

-- ===== 생활용품 (98-100) =====
('크리넥스 화장지', 'cat-tissue', 9.20, '크리넥스 3겹 화장지 30롤입니다. 부드럽고 흡수력이 뛰어납니다. 가정 필수품으로 넉넉하게 구비해두세요.', true, 'N', 1, 0, 100),
('테크 세탁세제', 'cat-detergent', 11.50, '테크 고농축 세탁세제입니다. 강력한 세척력으로 찌든 때도 깨끗하게 제거합니다. 섬유 손상 없이 세탁할 수 있습니다.', true, 'N', 1, 1, 80),
('퍼실 세탁세제', 'cat-detergent', 13.80, '독일 퍼실 세탁세제입니다. 프리미엄 세척력과 은은한 향이 특징입니다. 섬유 깊숙이 침투하여 때를 제거합니다.', true, 'N', 1, 2, 60)
